// Inputs available: this node receives Information Extraction output.
// Pull parsed doc text + extracted fields from the upstream Upstage nodes by name.
let docNode = {};
let ieNode = {};
let normNode = {};
try { docNode = $('Document Parse').item.json || {}; } catch (e) {}
try { ieNode = $('Information Extraction').item.json || {}; } catch (e) {}
try { normNode = $('Normalize Input').item.json || {}; } catch (e) {}

const docContent = docNode.content || {};
const parsedText = typeof docContent.text === 'string' ? docContent.text : '';
const pageCount = (docNode.usage && typeof docNode.usage.pages === 'number') ? docNode.usage.pages : 0;

// Information Extraction returns choices[0].message.content as a JSON STRING.
let extracted = {};
try {
  const raw = ieNode.choices && ieNode.choices[0] && ieNode.choices[0].message ? ieNode.choices[0].message.content : '{}';
  extracted = typeof raw === 'string' ? JSON.parse(raw) : (raw || {});
} catch (e) { extracted = {}; }

const schemaKeys = ['goal','decisions','action_items','participants','deadlines','risks'];
function populated(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return v.trim() !== '';
  if (Array.isArray(v)) return v.length > 0;
  return true;
}
const fieldsPopulated = schemaKeys.filter((k) => populated(extracted[k])).length;

// Build an enriched transcript context for Solar: original transcript + parsed doc + extracted fields.
const extractedSummary = JSON.stringify(extracted);
const MAX_DOC_CHARS = 8000; // cap text fed to Solar to keep latency sane; full length still reported below
const parsedForSolar = parsedText.length > MAX_DOC_CHARS ? (parsedText.slice(0, MAX_DOC_CHARS) + '\n...[truncated for prompt; full document parsed]') : parsedText;
const baseTranscript = normNode.transcript || '';
const enrichedTranscript = [
  baseTranscript ? ('Pasted notes:\n' + baseTranscript) : '',
  parsedForSolar ? ('Parsed source document:\n' + parsedForSolar) : '',
  extractedSummary && extractedSummary !== '{}' ? ('Structured fields extracted from document:\n' + extractedSummary) : ''
].filter(Boolean).join('\n\n');

return {
  json: {
    meetingTitle: normNode.meetingTitle || '',
    transcript: enrichedTranscript,
    deliveryType: normNode.deliveryType || 'website_brief',
    recipient: normNode.recipient || '',
    tone: normNode.tone || 'professional',
    requested_at: normNode.requested_at || new Date().toISOString(),
    // pipeline attribution carried forward to Assemble Response
    _pipeline: {
      documentParse: {
        pageCount: pageCount,
        charsExtracted: parsedText.length,
        sourceType: normNode.sourceType || ''
      },
      informationExtract: {
        schemaFields: schemaKeys.length,
        fieldsPopulated: fieldsPopulated
      }
    }
  }
};

// No file uploaded: feed the existing transcript text straight to Solar.
const j = $json;
return {
  json: {
    meetingTitle: j.meetingTitle || '',
    transcript: j.transcript || '',
    deliveryType: j.deliveryType || 'website_brief',
    recipient: j.recipient || '',
    tone: j.tone || 'professional',
    requested_at: j.requested_at || new Date().toISOString(),
    _pipeline: {}
  }
};

