// ---- Assemble Response (extended Parse Upstage Response) ----
// Pull pipeline attribution carried from the pre-Solar branch.
let _pipelineCtx = {};
try { _pipelineCtx = ($('Merge Doc Context').item.json && $('Merge Doc Context').item.json._pipeline) || {}; } catch (e) {}
if (!_pipelineCtx || Object.keys(_pipelineCtx).length === 0) {
  try { _pipelineCtx = ($('Text Only Path').item.json && $('Text Only Path').item.json._pipeline) || {}; } catch (e) {}
}
const content =
  $json.choices?.[0]?.message?.content ??
  $json.message?.content ??
  $json.content ??
  '{}';

const requiredSections = ['meetingUnderstanding', 'deliverablePack', 'executionMemory', 'harness'];

function stripJsonFence(value) {
  return String(value)
    .trim()
    .replace(/^\uFEFF/, '')
    .replace(/^```(?:json)?s*/i, '')
    .replace(/s*```$/i, '')
    .trim();
}

function extractBalancedJsonObject(value) {
  const text = stripJsonFence(value);
  const first = text.indexOf('{');
  if (first === -1) return text;

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = first; i < text.length; i++) {
    const char = text[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (char === '\\') {
      escaped = true;
      continue;
    }

    if (char === '"') {
      inString = !inString;
      continue;
    }

    if (inString) continue;

    if (char === '{') depth += 1;
    if (char === '}') depth -= 1;

    if (depth === 0) return text.slice(first, i + 1);
  }

  return text.slice(first);
}

function coerceString(value, fallback = '') {
  if (typeof value === 'string') return value.trim();
  if (value === null || value === undefined) return fallback;
  return String(value);
}

function coerceArray(value) {
  if (Array.isArray(value)) return value.map((entry) => coerceString(entry)).filter(Boolean);
  if (typeof value === 'string' && value.trim()) return [value.trim()];
  return [];
}

function coerceBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return ['true', 'yes', '1'].includes(value.toLowerCase());
  return Boolean(value);
}

function normalizeContract(raw) {
  const meetingUnderstanding = raw.meetingUnderstanding ?? {};
  const deliverablePack = raw.deliverablePack ?? {};
  const executionMemory = raw.executionMemory ?? {};
  const harness = raw.harness ?? {};
  const missingSections = requiredSections.filter(
    (section) => !raw[section] || typeof raw[section] !== 'object' || Array.isArray(raw[section]),
  );

  return {
    success: missingSections.length === 0,
    meetingUnderstanding: {
      goal: coerceString(meetingUnderstanding.goal),
      customerContext: coerceString(meetingUnderstanding.customerContext),
      keyDecisions: coerceArray(meetingUnderstanding.keyDecisions),
      requirements: coerceArray(meetingUnderstanding.requirements),
      missingInfo: coerceArray(meetingUnderstanding.missingInfo),
      risks: coerceArray(meetingUnderstanding.risks),
    },
    deliverablePack: {
      type: coerceString(deliverablePack.type, 'website_brief'),
      title: coerceString(deliverablePack.title),
      customerMessage: coerceString(deliverablePack.customerMessage),
      brief: coerceString(deliverablePack.brief),
      lovablePrompt: coerceString(deliverablePack.lovablePrompt),
      prd: coerceString(deliverablePack.prd),
      tasks: coerceArray(deliverablePack.tasks),
    },
    executionMemory: {
      previousContextUsed: coerceBoolean(executionMemory.previousContextUsed),
      nextActions: coerceArray(executionMemory.nextActions),
      memoryToPersist: coerceArray(executionMemory.memoryToPersist),
      continuationPrompt: coerceString(executionMemory.continuationPrompt),
    },
    harness: {
      doneEvidence: coerceArray(harness.doneEvidence),
      missingEvidence: coerceArray(harness.missingEvidence),
      qualityChecklist: coerceArray(harness.qualityChecklist),
      nextVerificationStep: coerceString(harness.nextVerificationStep),
    },
    _warnings: missingSections.map((section) => 'Missing required section: ' + section),
    _error: missingSections.length ? 'UPSTAGE_RESPONSE_CONTRACT_INCOMPLETE' : null,
    generated_at: new Date().toISOString(),
  };
}

function failureResponse(reason, detail) {
  return {
    success: false,
    meetingUnderstanding: {
      goal: '',
      customerContext: '',
      keyDecisions: [],
      requirements: [],
      missingInfo: ['Upstage response could not be parsed into the expected Execution Memory contract.'],
      risks: [reason],
    },
    deliverablePack: {
      type: 'error_report',
      title: 'Execution Memory generation needs review',
      customerMessage: '',
      brief: detail,
      tasks: [],
    },
    executionMemory: {
      previousContextUsed: false,
      nextActions: [
        'Review the raw Upstage response in n8n execution logs.',
        'Rerun the workflow after fixing the response contract.',
      ],
      memoryToPersist: [],
      continuationPrompt: 'Repair the Upstage response so it returns valid JSON with the required Execution Memory sections.',
    },
    harness: {
      doneEvidence: [],
      missingEvidence: ['Valid JSON response from Upstage', 'Four required Execution Memory sections'],
      qualityChecklist: ['No silent fallback for production E2E', 'n8n execution log reviewed'],
      nextVerificationStep: 'Open the n8n execution, inspect the Upstage node output, then rerun the Lovable debug test.',
    },
    _warnings: [reason],
    _error: detail,
    _raw: { content: String(content).slice(0, 4000) },
    generated_at: new Date().toISOString(),
  };
}

function attachPipeline(result) {
  const pipeline = {};
  if (_pipelineCtx && _pipelineCtx.documentParse) pipeline.documentParse = _pipelineCtx.documentParse;
  if (_pipelineCtx && _pipelineCtx.informationExtract) pipeline.informationExtract = _pipelineCtx.informationExtract;
  const dp = (result && result.deliverablePack) || {};
  let deliverablesGenerated = 0;
  ['tasks'].forEach((k) => { if (Array.isArray(dp[k])) deliverablesGenerated += dp[k].length; });
  ['title','customerMessage','brief','lovablePrompt','prd'].forEach((k) => { if (typeof dp[k] === 'string' && dp[k].trim()) deliverablesGenerated += 1; });
  pipeline.solar = { model: 'solar-pro3', deliverablesGenerated: deliverablesGenerated };
  result.pipeline = pipeline;
  if (result._error === undefined) result._error = null;
  else if (typeof result._error === 'string' && result._error) {
    result._error = { code: result._error, message: result._error, stage: 'solar' };
  }
  return result;
}

let parsed;
try {
  parsed = JSON.parse(extractBalancedJsonObject(content));
} catch (error) {
  return { json: attachPipeline(failureResponse('UPSTAGE_JSON_PARSE_FAILED', error.message)) };
}

return { json: attachPipeline(normalizeContract(parsed)) };

// Receives error output from one of the three Upstage HTTP nodes.
// Determines which stage failed and returns a minimal valid HandoffResponse shape
// with _error.stage set so the frontend error view can name the stage.
const STAGE = $json.__stage || 'solar';
const errObj = $json.error || $json;
const code = (errObj && (errObj.code || errObj.name)) || 'UPSTAGE_NODE_ERROR';
const message = (errObj && (errObj.message || errObj.description)) || ('Upstage ' + STAGE + ' request failed');

return {
  json: {
    success: false,
    meetingUnderstanding: {
      goal: '', customerContext: '', keyDecisions: [], requirements: [],
      missingInfo: ['Upstage ' + STAGE + ' stage failed before generation completed.'],
      risks: [String(code)]
    },
    deliverablePack: {
      type: 'error_report',
      title: 'Handoff pipeline failed at ' + STAGE,
      customerMessage: '', brief: String(message), tasks: [],
      lovablePrompt: '', prd: ''
    },
    executionMemory: {
      previousContextUsed: false,
      nextActions: ['Inspect the ' + STAGE + ' node output in n8n execution logs.', 'Retry after resolving the Upstage error.'],
      memoryToPersist: [],
      continuationPrompt: 'Resolve the Upstage ' + STAGE + ' failure and rerun the Handoff pipeline.'
    },
    harness: {
      doneEvidence: [],
      missingEvidence: ['Successful ' + STAGE + ' response'],
      qualityChecklist: ['Upstage credential valid', 'Input payload well-formed'],
      nextVerificationStep: 'Open the n8n execution and inspect the ' + STAGE + ' node error.'
    },
    pipeline: { solar: { model: 'solar-pro3', deliverablesGenerated: 0 } },
    _error: { code: String(code), message: String(message), stage: STAGE },
    generated_at: new Date().toISOString()
  }
};

const j = $json || {};
j.__stage = 'documentParse';
return { json: j };

const j = $json || {};
j.__stage = 'informationExtract';
return { json: j };

const j = $json || {};
j.__stage = 'solar';
return { json: j };
